import { useForm, useFieldArray } from 'react-hook-form';

function PedidoForm() {
  const { control, register, handleSubmit } = useForm({
    defaultValues: {
      itens: [{ produto: '', quantidade: 1 }]
    }
  });

  const { fields, append, remove } = useFieldArray({
    control,
    name: 'itens'
  });

  return (
    <form onSubmit={handleSubmit((data) => console.log(data))}>
      {fields.map((field, index) => (
        <div key={field.id}>
          <input {...register(`itens.${index}.produto`)} placeholder="Produto" />
          <input
            type="number"
            {...register(`itens.${index}.quantidade`, { valueAsNumber: true })}
          />
          <button type="button" onClick={() => remove(index)}>Remover</button>
        </div>
      ))}

      <button type="button" onClick={() => append({ produto: '', quantidade: 1 })}>
        Adicionar Item
      </button>
      <button type="submit">Enviar Pedido</button>
    </form>
  );
}

import { useForm, FormProvider, useFormContext } from 'react-hook-form';

function EnderecoFields() {
  const { register, formState: { errors } } = useFormContext();
  return (
    <>
      <input {...register('endereco.rua')} placeholder="Rua" />
      <input {...register('endereco.cidade')} placeholder="Cidade" />
    </>
  );
}

function CadastroCompleto() {
  const methods = useForm();
  return (
    <FormProvider {...methods}>
      <form onSubmit={methods.handleSubmit(console.log)}>
        <input {...methods.register('nome')} placeholder="Nome" />
        <EnderecoFields />
        <button type="submit">Salvar</button>
      </form>
    </FormProvider>
  );
}
